#include<iostream>
#include<vector>
#include<algorithm>
using namespace std;

class Solution {
public:
bool solve(vector<int>& c, int n, int m) {
  // read input
  for (int i = 0; i < c.size(); i++) {
    cin >> c[i];
  }
  cin >> n >> m;

  int sum = 0;
  for (int num : c) {
    sum += num;
  }

  return sum >= n;
}
};

int main() {
  int t;
  cin >> t;
  while (t--) {
    vector<int> c;
    int n, m;
    for (int i = 0; i < m; i++) {
      int num;
      cin >> num;
      c.push_back(num);
    }
    cin >> n >> m;
    Solution s;
    bool res = s.solve(c, n, m);
    cout << (res ? 'Yes' : 'No') << endl;
  }
  return 0;
}
